sql:
SELECT COUNT(*)
FROM traders
WHERE role = 'retail' AND registration_date < '2020-01-01';

SELECT trddt, stkcd, hiprc, loprc
FROM trade_data
WHERE trddt = '2022-01-01' AND stkcd = 1;

SELECT COUNT(*)
FROM trade_data
WHERE trddt = '2022-10-01';

SELECT `return`
FROM strategy_performance
WHERE strategy_id = 1 AND performance_id = 2;

SELECT index_name
FROM market_indexes
WHERE base_value > 100.0;

SELECT rm.trader_id
FROM risk_management rm
WHERE rm.risk_tolerance > (
    SELECT AVG(return) AS avg_strategy_return
    FROM strategy_performance
);

SELECT T1.trader_name, T2.balance
FROM traders AS T1
INNER JOIN account_balances AS T2 ON T1.trader_id = T2.trader_id;

SELECT email, role, account_type, registration_date 
FROM traders 
WHERE trader_id = 1;

SELECT trader_id, risk_tolerance, stop_loss
FROM risk_management
WHERE risk_tolerance < 5 AND stop_loss > (SELECT AVG(stop_loss) FROM risk_management);

SELECT stkcd
FROM trade_data
WHERE opnprc > (SELECT AVG(opnprc) FROM trade_data);
